{
  "schemaVersion": "1.0",
  "message": "Unit tests cover lockout window logic, enumeration-safe responses, session TTL selection, and logging; functional tests validate Login UI error messaging and Remember me behavior with mocked API.",
  "testPlan": [
    {
      "title": "Service: unknown email returns 401 with generic message, dummy verify executed, logs UNKNOWN_EMAIL",
      "description": "Given a non-existent email, when authenticate(email, password) is called, then the service performs a dummy constant-time password verification, logs reason=UNKNOWN_EMAIL with email and timestamp, and returns an error mapped to HTTP 401 with message 'We couldn’t sign you in. Check your email and password.'",
      "type": "unit"
    },
    {
      "title": "Service: wrong password increments counter, logs BAD_PASSWORD, returns 401 with generic message",
      "description": "Given an active account and an incorrect password within the failure window, when authenticate is called, then failed_signin_count increments, last_failed_signin_at updates, reason=BAD_PASSWORD is logged with metadata, and an error mapped to HTTP 401 with the generic message is returned.",
      "type": "unit"
    },
    {
      "title": "Service: disabled account denied, counts as failure, logs STATUS_NOT_ELIGIBLE, returns 401 generic",
      "description": "Given a user with status=disabled, when authenticate is called, then the attempt is treated as a failure for counter purposes, counters update per window rules, reason=STATUS_NOT_ELIGIBLE with status=disabled is logged, and an error mapped to HTTP 401 with the generic message is returned without revealing status.",
      "type": "unit"
    },
    {
      "title": "Service: invited account denied, counts as failure, logs STATUS_NOT_ELIGIBLE, returns 401 generic",
      "description": "Given a user with status=invited, when authenticate is called, then the attempt increments failure counters per window rules, logs reason=STATUS_NOT_ELIGIBLE with status=invited, and returns an error mapped to HTTP 401 with the generic message with no account state revealed.",
      "type": "unit"
    },
    {
      "title": "Service: locked-out account short-circuits with 401 generic and no password check; logs LOCKED_OUT",
      "description": "Given lockout_until > now for an account, when authenticate is called, then password verification is skipped, reason=LOCKED_OUT is logged, and an error mapped to HTTP 401 with the same generic message is returned.",
      "type": "unit"
    },
    {
      "title": "Failure handling: increment counters within window below threshold",
      "description": "Given last_failed_signin_at is within AUTH_FAILED_WINDOW_MIN and failed_signin_count < AUTH_FAILED_THRESHOLD-1, when a new failure occurs, then failed_signin_count increments by 1 and last_failed_signin_at is updated to now; lockout_until remains NULL.",
      "type": "unit"
    },
    {
      "title": "Failure handling: reaching threshold sets lockout_until and resets counters",
      "description": "Given failures within AUTH_FAILED_WINDOW_MIN reach AUTH_FAILED_THRESHOLD, when the latest failure is processed, then lockout_until is set to now + AUTH_LOCKOUT_MIN, failed_signin_count resets to 0, and last_failed_signin_at is cleared.",
      "type": "unit"
    },
    {
      "title": "Failure handling: window reset after inactivity",
      "description": "Given last_failed_signin_at is older than AUTH_FAILED_WINDOW_MIN, when a new failure occurs, then failed_signin_count is reset to 1 and last_failed_signin_at is set to now (no immediate lockout).",
      "type": "unit"
    },
    {
      "title": "Auto-unlock: attempts after lockout_until are evaluated normally",
      "description": "Given lockout_until <= now, when authenticate is called, then the service proceeds to evaluate status/password normally (no lockout short-circuit) and does not re-lock unless new failures recur.",
      "type": "unit"
    },
    {
      "title": "Success path: counters and lockout cleared; lastLoginAt updated",
      "description": "Given prior failures and/or a past lockout, when correct credentials are provided, then failed_signin_count=0, last_failed_signin_at=NULL, lockout_until=NULL, and last_login_at is updated to now.",
      "type": "unit"
    },
    {
      "title": "Controller: all failure causes map to HTTP 401 with identical generic message",
      "description": "Given service errors for UNKNOWN_EMAIL, BAD_PASSWORD, STATUS_NOT_ELIGIBLE, or LOCKED_OUT, when the controller handles /login, then the response status is 401 and the JSON body contains the exact message 'We couldn’t sign you in. Check your email and password.' for each case.",
      "type": "unit"
    },
    {
      "title": "Controller: failure response contains only generic message (no state details)",
      "description": "Given any failed sign-in, when the controller responds, then the JSON body includes only a 'message' field (no status, reason, lockout data, or user hints).",
      "type": "unit"
    },
    {
      "title": "Session issuance: rememberMe=true sets 30-day idle timeout and persistent cookie",
      "description": "Given rememberMe=true at login, when a session is issued, then the server-side idle TTL is AUTH_REMEMBER_TTL_DAYS (default 30 days, sliding) and the cookie has Max-Age for 30 days with HttpOnly and Secure set and SameSite per configured policy.",
      "type": "unit"
    },
    {
      "title": "Session issuance: rememberMe=false uses default 8-hour idle timeout",
      "description": "Given rememberMe is not selected, when a session is issued, then the server idle TTL remains 8 hours and the cookie is a session cookie or has Max-Age for 8 hours per current implementation.",
      "type": "unit"
    },
    {
      "title": "Audit logging: failure reasons and metadata are recorded",
      "description": "Given any failed sign-in or lockout event, when processed, then an audit log entry is emitted with reason (e.g., UNKNOWN_EMAIL, BAD_PASSWORD, STATUS_NOT_ELIGIBLE, LOCKED_OUT), userId or normalized email, failed_count, lockout_until (if applicable), ip (if available), and timestamp.",
      "type": "unit"
    },
    {
      "title": "Login UI: shows generic error on API 401 (unknown email)",
      "description": "Given the Login form and MSW returns 401 with the generic message for an unknown email attempt, when the user submits, then the UI displays exactly 'We couldn’t sign you in. Check your email and password.' and no additional hints.",
      "type": "functional"
    },
    {
      "title": "Login UI: shows same generic error on API 401 when account is locked",
      "description": "Given MSW returns 401 for a locked account attempt, when the user submits, then the UI displays the same generic error text and does not show countdowns or status-specific messaging.",
      "type": "functional"
    },
    {
      "title": "Login UI: Remember me checkbox is unchecked by default",
      "description": "Given the /login screen renders, then the Remember me checkbox is not selected until the user explicitly checks it.",
      "type": "functional"
    },
    {
      "title": "Login UI: request includes rememberMe=true when checkbox selected",
      "description": "Given the user checks Remember me and submits valid credentials, when the login request is sent, then the payload contains rememberMe=true; when unchecked, rememberMe is false or omitted per client contract.",
      "type": "functional"
    },
    {
      "title": "Login UI: clears error on subsequent successful sign-in",
      "description": "Given a prior 401 displayed the generic error, when the next sign-in succeeds (MSW returns 200), then the error message is removed from the UI.",
      "type": "functional"
    },
    {
      "title": "Remember me persists session across page reload in mocked environment",
      "description": "Given MSW simulates setting a persistent auth cookie on success with rememberMe=true, when the test simulates a page reload, then the app initializes as authenticated (e.g., no redirect back to /login), indicating persistence across restarts.",
      "type": "functional"
    },
    {
      "title": "Non-Remember me session does not persist across page reload in mocked environment",
      "description": "Given MSW simulates a session cookie on success with rememberMe=false, when the test simulates a page reload, then the app initializes unauthenticated (e.g., shows /login), indicating non-persistent default behavior.",
      "type": "functional"
    }
  ],
  "openQuestions": []
}
